1	/**
2	 * OKKI 全量同步 - 滚动加载所有会话后再提取
3	 * 解决 __conversationListFullData__ 只包含可视范围会话的问题
4	 */
5	const { chromium } = require('playwright');
6	const fs = require('fs');
7	const path = require('path');
8	
9	const PROFILE = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Profile 4';
10	const DATA_DIR = path.join(__dirname, '..', 'data');
11	const CDP_URL = 'http://localhost:9222';
12	
13	function ts() { return new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19); }
14	function log(msg) { console.log(`[${new Date().toLocaleTimeString()}] ${msg}`); }
15	function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
16	
17	async function main() {
18	  let browser, page;
19	
20	  // ---- 连接或启动 Chrome ----
21	  const http = require('http');
22	  let cdpAvailable = false;
23	  try {
24	    await new Promise((resolve, reject) => {
25	      const req = http.get('http://127.0.0.1:9222/json/version', (res) => {
26	        let data = '';
27	        res.on('data', c => data += c);
28	        res.on('end', () => {
29	          try { resolve(!!JSON.parse(data).webSocketDebuggerUrl); } catch (e) { resolve(false); }
30	        });
31	      });
32	      req.on('error', () => resolve(false));
33	      req.setTimeout(2000, () => { req.destroy(); resolve(false); });
34	    });
35	  } catch (e) {}
36	
37	  if (cdpAvailable) {
38	    log('CDP连接已有Chrome...');
39	    browser = await chromium.connectOverCDP(CDP_URL);
40	    const pages = browser.contexts()[0].pages();
41	    page = pages.find(p => p.url().includes('xiaoman') || p.url().includes('onetalk'));
42	    if (!page) page = await browser.contexts()[0].newPage();
43	  } else {
44	    log('启动 Chrome (Profile 4)...');
45	    browser = await chromium.launchPersistentContext(PROFILE, {
46	      channel: 'chrome',
47	      headless: false,
48	      viewport: { width: 1440, height: 900 },
49	    });
50	    page = await browser.newPage();
51	  }
52	
53	  // ---- 导航 + 登录检测 ----
54	  if (!page.url().includes('xiaoman') && !page.url().includes('onetalk')) {
55	    await page.goto('https://crm.xiaoman.cn/im/', { waitUntil: 'domcontentloaded', timeout: 30000 }).catch(() => {});
56	  }
57	
58	  if (page.url().includes('login')) {
59	    log('');
60	    log('========================================');
61	    log('  请在浏览器中登录 OKKI');
62	    log('  登录后自动继续...');
63	    log('========================================');
64	    log('');
65	    const start = Date.now();
66	    while (Date.now() - start < 5 * 60 * 1000) {
67	      if (!page.url().includes('login')) { log('登录成功！'); break; }
68	      await sleep(2000);
69	    }
70	    if (page.url().includes('login')) { log('超时'); await browser.close(); return; }
71	  } else {
72	    log('已登录');
73	  }
74	
75	  await sleep(3000);
76	
77	  // ---- 等 onetalk iframe ----
78	  let otFrame = null;
79	  for (let i = 0; i < 30; i++) {
80	    const frames = page.frames();
81	    otFrame = frames.find(f => f.url().startsWith('https://onetalk.alibaba.com/'));
82	    if (otFrame) { log(`onetalk 已加载`); break; }
83	    if (i === 0) {
84	      log(`等待 onetalk... (${frames.length} frames)`);
85	      for (const f of frames) log(`  ${f.url().slice(0, 100)}`);
86	    }
87	    await sleep(2000);
88	  }
89	
90	  if (!otFrame) {
91	    log('onetalk 未加载。请在OKKI中点击TM标签页，确保能看到会话列表。');
92	    await sleep(30000);
93	    const frames = page.frames();
94	    otFrame = frames.find(f => f.url().startsWith('https://onetalk.alibaba.com/'));
95	    if (!otFrame) { log('仍然未找到'); await browser.close(); return; }
96	  }
97	
98	  // ---- 等初始数据 ----
99	  await sleep(3000);
100	  let initialCount = await otFrame.evaluate(() => (window.__conversationListFullData__ || []).length);
101	  log(`初始会话数: ${initialCount}`);
102	
103	  // ---- 滚动加载全部会话 ----
104	  log('开始滚动加载全部会话...');
105	  let lastCount = initialCount;
106	  let unchangedRounds = 0;
107	
108	  for (let round = 0; round < 50; round++) {
109	    const scrollResult = await otFrame.evaluate(() => {
110	      // 找会话列表容器（通常是一个有很多子div的可滚动div）
111	      let best = null;
112	      let bestScore = 0;
113	      for (const el of document.querySelectorAll('div')) {
114	        const childCount = el.children.length;
115	        const scrollDiff = el.scrollHeight - el.clientHeight;
116	        if (childCount > 20 && scrollDiff > 200) {
117	          const score = childCount + scrollDiff;
118	          if (score > bestScore) { best = el; bestScore = score; }
119	        }
120	      }
121	      if (!best) return { done: true, count: (window.__conversationListFullData__ || []).length };
122	
123	      const before = (window.__conversationListFullData__ || []).length;
124	      best.scrollTop = best.scrollHeight;
125	      return { done: false, before, scrollH: best.scrollHeight, clientH: best.clientHeight };
126	    });
127	
128	    if (scrollResult.done) { log('  找不到合适的滚动容器'); break; }
129	
130	    await sleep(2000);
131	
132	    const newCount = await otFrame.evaluate(() => (window.__conversationListFullData__ || []).length);
133	    if (round % 3 === 0 || newCount !== lastCount) {
134	      log(`  第${round+1}轮: ${scrollResult.before} → ${newCount}`);
135	    }
136	
137	    if (newCount === lastCount) {
138	      unchangedRounds++;
139	      if (unchangedRounds >= 3) { log('  数据已稳定'); break; }
140	    } else {
141	      unchangedRounds = 0;
142	    }
143	    lastCount = newCount;
144	  }
145	
146	  // ---- 提取全量数据 ----
147	  const finalCount = await otFrame.evaluate(() => (window.__conversationListFullData__ || []).length);
148	  log(`最终会话总数: ${finalCount} (初始: ${initialCount})`);
149	
150	  const fullData = await otFrame.evaluate(() => {
151	    const convs = window.__conversationListFullData__ || [];
152	    return convs.map(c => ({
153	      cid: c.cid, name: c.name, loginId: c.loginId, aliId: c.aliId,
154	      accountId: c.accountId, companyName: c.companyName,
155	      country: c.country, level: c.level,
156	      serviceType: c.serviceType, conversationType: c.conversationType,
157	      unreadCount: c.unreadCount,
158	      lastContactTime: c.lastContactTime,
159	      lastContactTimeLong: c.lastContactTimeLong,
160	      complianceCountryCode: c.complianceCountryCode,
161	      latestMessage: c.latestMessage ? {
162	        content: c.latestMessage.content,
163	        messageType: c.latestMessage.messageType,
164	        messageId: c.latestMessage.messageId,
165	        contactRead: c.latestMessage.contactRead,
166	      } : null,
167	    }));
168	  });
169	
170	  // 保存
171	  const metaPath = path.join(DATA_DIR, 'tm_conversations_latest.json');
172	  fs.writeFileSync(metaPath, JSON.stringify({ exportedAt: new Date().toISOString(), total: finalCount, conversations: fullData }, null, 2));
173	  log(`已保存: tm_conversations_latest.json (${finalCount} 会话)`);
174	
175	  // ---- 搜索目标客户 ----
176	  const targets = ['Abigail', 'Mutuku', 'Noslen', 'Gonzalez', 'ivy', 'quarcoo', 'Elton', 'Nadia', 'Samia', 'Guenad'];
177	  const foundNames = new Set();
178	  for (const t of targets) {
179	    for (const c of fullData) {
180	      const haystack = JSON.stringify([c.name, c.companyName, c.loginId]).toLowerCase();
181	      if (haystack.includes(t.toLowerCase())) {
182	        foundNames.add(c.name);
183	      }
184	    }
185	  }
186	
187	  if (foundNames.size > 0) {
188	    log(`找到匹配客户: ${[...foundNames].join(', ')}`);
189	  } else {
190	    log('未找到5个目标客户，列出所有有未读的:');
191	    const unread = fullData.filter(c => c.unreadCount > 0);
192	    if (unread.length === 0) {
193	      log('  所有会话 unreadCount 均为 0 — 数据源可能不支持此字段');
194	    } else {
195	      for (const c of unread) {
196	        log(`  [${c.unreadCount}] ${c.name} | ${(c.latestMessage?.content||'').slice(0, 70)}`);
197	      }
198	    }
199	  }
200	
201	  // 打印前30个名字供对比
202	  log('');
203	  log('前30个会话:');
204	  for (let i = 0; i < Math.min(30, fullData.length); i++) {
205	    log(`  ${i+1}. ${fullData[i].name}`);
206	  }
207	
208	  await browser.close();
209	  log('完成。');
210	}
211	
212	main().catch(e => { log(`错误: ${e.message}`); console.error(e); process.exit(1); });
