449	async function installLwp(cdpClient, iframeSessionId) {
450	  const expr = `
451	    (function() {
452	      var _send = WebSocket.prototype.send;
453	      var _ae = WebSocket.prototype.addEventListener;
454	
455	      window.__lwpPending = {};
456	      window.__lwpSeq = 0;
457	
458	      WebSocket.prototype.send = function(data) {
459	        if (!window.__lwpWs && this.readyState === 1) {
460	          window.__lwpWs = this;
461	          _ae.call(this, 'message', function(event) {
462	            try {
463	              var raw = typeof event.data === 'string' ? event.data : '';
464	              if (raw.indexOf('"code"') < 0) return;
465	              var parsed = JSON.parse(raw);
466	              var mid = parsed.headers && parsed.headers.mid;
467	              if (mid && window.__lwpPending[mid]) {
468	                var p = window.__lwpPending[mid];
469	                delete window.__lwpPending[mid];
470	                p.resolve(parsed);
471	              }
472	            } catch(e) {}
473	          });
474	          console.log('[LWP] WS captured: ' + this.url);
475	        }
476	        return _send.call(this, data);
477	      };
478	
479	      window.__lwpRequest = function(lwpPath, body) {
480	        return new Promise(function(resolve, reject) {
481	          var ws = window.__lwpWs;
482	          if (!ws || ws.readyState !== 1) { reject(new Error('WS not ready')); return; }
483	          var mid = Date.now() + ' ' + (++window.__lwpSeq);
484	          var req = JSON.stringify({ lwp: lwpPath, headers: { mid: mid }, body: body });
485	          window.__lwpPending[mid] = { resolve: resolve, reject: reject };
486	          ws.send(req);
487	          setTimeout(function() {
488	            if (window.__lwpPending[mid]) { delete window.__lwpPending[mid]; reject(new Error('timeout')); }
489	          }, 30000);
490	        });
491	      };
492	
493	      return JSON.stringify({ installed: true });
494	    })()
495	  `;
496	
497	  return sendToTarget(cdpClient, iframeSessionId, 3, expr);
498	}
