500	async function evalInIframe(cdpClient, iframeSessionId, id, expression, awaitPromise) {
501	  const raw = await sendToTarget(cdpClient, iframeSessionId, id, expression, awaitPromise);
502	  if (!raw) return raw;
503	  try { return JSON.parse(raw); } catch (e) { return raw; }
504	}
