506	async function sendToTarget(cdpClient, sessionId, id, expression, awaitPromise) {
507	  return new Promise((resolve) => {
508	    const timeout = setTimeout(() => resolve(null), 35000);
509	
510	    const handler = (msg) => {
511	      if (sessionId && msg.sessionId !== sessionId) return;
512	      try {
513	        const m = JSON.parse(msg.message);
514	        if (m.id === id) {
515	          clearTimeout(timeout);
516	          cdpClient.off('Target.receivedMessageFromTarget', handler);
517	          if (m.result?.result?.value !== null && m.result?.result?.value !== undefined) {
518	            resolve(m.result.result.value);
519	          } else if (m.result) {
520	            resolve(m.result);
521	          } else {
522	            resolve(null);
523	          }
524	        }
525	      } catch (e) { clearTimeout(timeout); resolve(null); }
526	    };
527	
528	    cdpClient.on('Target.receivedMessageFromTarget', handler);
529	
530	    cdpClient.send('Target.sendMessageToTarget', {
531	      sessionId: sessionId || cdpClient._sessionId,
532	      message: JSON.stringify({
533	        id,
534	        method: 'Runtime.evaluate',
535	        params: { expression, awaitPromise: !!awaitPromise, returnByValue: true }
536	      })
537	    }).catch(() => { clearTimeout(timeout); resolve(null); });
538	  });
539	}
